import { page } from 'vitest/browser';
import { describe, expect, it } from 'vitest';
import { render } from 'vitest-browser-svelte';
import Page from './+page.svelte';

describe('/+page.svelte', () => {
	it('renders the selector sidebar and chat area', async () => {
		render(Page);
		// Chat pane: active chat heading (h2 with the selected partner's name)
		await expect
			.element(page.getByRole('heading', { name: 'Claudia', level: 2 }))
			.toBeInTheDocument();
		// Input area present
		await expect.element(page.getByRole('button', { name: 'Send' })).toBeInTheDocument();
	});

	describe('layout', () => {
		it('input bottom is flush with selector bottom', () => {
			render(Page);
			const selector = document.querySelector('.selector')!;
			const input = document.querySelector('.input')!;
			const { bottom: selectorBottom } = selector.getBoundingClientRect();
			const { bottom: inputBottom } = input.getBoundingClientRect();
			// Allow 1px for sub-pixel rounding
			expect(Math.abs(selectorBottom - inputBottom)).toBeLessThanOrEqual(1);
		});
	});
});

import { md, type ChatAppState, type Markdown } from './types.js';

/** Singleton reactive state for the entire chat application. */
export const appState: ChatAppState = $state({
	player: {
		name: 'You',
		profilePicture: '',
		status: 'active',
		statusText: md('Online')
	},
	currentlySelected: 0,
	chats: [
		{
			name: 'Claudia',
			profilePicture: '',
			status: 'active',
			statusText: md('Always here for you ♡'),
			messages: []
		},
		{
			name: 'Jordan',
			profilePicture: '',
			status: 'offline',
			statusText: md('Be back soon'),
			messages: [
				{
					role: 'partner',
					text: md('sorry, heading to bed — catch you tomorrow!'),
					time: new Date()
				}
			]
		},
		{
			name: 'Sam',
			profilePicture: '',
			status: 'busy',
			statusText: md('In a meeting'),
			messages: [
				{
					role: 'partner',
					text: md('swamped rn, talk later?'),
					time: new Date()
				}
			]
		},
		{
			name: 'Riley',
			profilePicture: '',
			status: 'away',
			statusText: md('stepped out'),
			messages: [
				{
					role: 'partner',
					text: md("afk for a bit, don't wait up"),
					time: new Date()
				}
			]
		},
		{
			name: 'Alex',
			profilePicture: '',
			status: 'offline',
			statusText: md(''),
			messages: [
				{
					role: 'partner',
					text: md("can't hang tonight, sorry"),
					time: new Date()
				}
			]
		}
	]
});

/** Called by the Game State layer to deliver a partner message into a chat. */
export function appendPartnerMessage(userIndex: number, message: Markdown): void {
	appState.chats[userIndex].messages.push({
		role: 'partner',
		text: message,
		time: new Date()
	});
}

