			for (let i = 0; i < 30; i++) {
				appState.chats[0].messages.push({
					role: 'user',
					text: md(`Message ${i}`),
					time: new Date()
				});
			}
			render(Page);
			const app = document.querySelector('.app')!;
			const ul = document.querySelector('ul')!;
